  saveValuesToDB<T>(tableName: string, values: T): Promise<void> {
    return this.db.object(`/${tableName}`).set(values);
  }

  getValuesFromDB<T>(tableName: string): Observable<T> {
    return this.db.object<T>(`/${tableName}`).valueChanges()
      .pipe(
        map(value => value as T || {} as T) // Provide a default value of type T
      );
  }


