  getCurrentDateFormatted(): string {
    const today = new Date();
    const yyyy = today.getFullYear();
    let mm = today.getMonth() + 1; // Months start at 0!
    let dd = today.getDate();

    // Pad single digit month and day with a leading zero
    const paddedMM = mm < 10 ? `0${mm}` : mm;
    const paddedDD = dd < 10 ? `0${dd}` : dd;

    return `${yyyy}-${paddedMM}-${paddedDD}`;
  }

  async getHebrewDate(gregorianDate: string, afterSunset: boolean): Promise<HebrewDate> {

    let url = "";

    if (afterSunset)

      url = `https://www.hebcal.com/converter?cfg=json&date=${gregorianDate}&g2h=1&strict=1&gs=on`;

    else

      url = `https://www.hebcal.com/converter?cfg=json&date=${gregorianDate}&g2h=1&strict=1&gs=off`;

    const response = await fetch(url);

    const data = await response.json();

    const { heDateParts } = data;



    // Remove quotation marks from the fields

    /*
    const year = heDateParts.y.replace(/[׳״]/g, '');

    const month = heDateParts.m.replace(/[׳״]/g, '');

    const day = heDateParts.d.replace(/[׳״]/g, '');
    */

    const year = heDateParts.y;

    const month = heDateParts.m;

    const day = heDateParts.d;


    // Return the formatted object

    return { year, month, day };

  }

