  calculateFullConsonantsOnlyValue(name: string): CalculationFullResult {
    const vowels: string[] = ['א', 'ה', 'ו', 'י', 'ע'];

    let calculationProcess = '';
    let totalOneDigit: number = 0;
    let total = name.split('').reduce((acc, curr, index) => {
      if (vowels.indexOf(curr) < 0) {
        const value = gematriaValues[curr] || 0;
        calculationProcess += value.toString();
        if (index < name.length - 1) {
          calculationProcess += ' + ';
        }
        return acc + value;
      } else {
        return acc;
      }
    }, 0);

    if (calculationProcess.endsWith(" + "))
      calculationProcess = calculationProcess.substring(0, calculationProcess.length - 3);

    // Reduce the total to a single digit and include the process
    let reducedTotal = total;
    while (reducedTotal > 9 && !this.areAllDigitsSame(reducedTotal)) {
      if (calculationProcess.endsWith(" = ")) {
        calculationProcess = calculationProcess.substring(0, calculationProcess.length - 4);
      }

      if (!calculationProcess.endsWith(reducedTotal.toString()))
        calculationProcess += ' = ' + reducedTotal.toString();
      reducedTotal = reducedTotal.toString().split('').reduce((acc, curr) => acc + parseInt(curr), 0);
    }

    // If the final reduction is not needed, just show the total
    if (total !== reducedTotal || reducedTotal <= 9) {
      totalOneDigit = reducedTotal;
      //if (total <= 9) {
      //  calculationProcess = calculationProcess.substring(0, calculationProcess.length - 3);
      //}
      calculationProcess += ' = ' + reducedTotal;
    }


    return {
      totalOneDigit,
      total,
      calculationProcess
    };
  }

