  calculateNumerologyNumber(num: number, check4Master = false, check4Karma = false): CalculationResult {
    const masterNumbers: number[] = [11, 22, 33, 44];
    const karmaNumbers: number[] = [13, 14, 16, 18, 19];
    const strongNumbers = [10, 12];
    const technicalNumbers: number[] = [28, 31];

    let state = {
      master: masterNumbers.includes(num),
      karma: karmaNumbers.includes(num),
      strong: strongNumbers.includes(num),
      technical: false
    };

    let number = num.toString();

    let calculationProcess = '';
    let total: number | string = '';
    let totalOneDigit: number = 0;
    if (check4Master || check4Karma) {
      total = num;
      calculationProcess = total.toString();
      let reducedTotal = total;
      while (reducedTotal > 9) {
        reducedTotal = reducedTotal.toString().split('').reduce((acc, curr) => acc + parseInt(curr), 0);
      }
      totalOneDigit = reducedTotal;
    } else {
      total = number.split('').reduce((acc, curr, index) => {
        const value = parseInt(curr);
        calculationProcess += value.toString();
        if (index < number.length - 1) {
          calculationProcess += ' + ';
        }
        return acc + value;
      }, 0);

      // Reduce the total to a single digit and include the process
      let reducedTotal = total;
      while (reducedTotal > 9) {
        calculationProcess += ' = ' + reducedTotal.toString();
        reducedTotal = reducedTotal.toString().split('').reduce((acc, curr) => acc + parseInt(curr), 0);
      }

      // If the final reduction is not needed, just show the total
      if (total !== reducedTotal || reducedTotal <= 9) {
        totalOneDigit = reducedTotal;
        if (total <= 9 && calculationProcess.includes('=')) {
          calculationProcess = calculationProcess.substring(0, calculationProcess.length - 3);
          calculationProcess += ' = ' + reducedTotal;
        } else
          calculationProcess += ' = ' + reducedTotal;
      }
    }

    if (!check4Master && !check4Karma) {
      state = {
        master: masterNumbers.includes(total as number),
        karma: karmaNumbers.includes(total as number),
        strong: strongNumbers.includes(num),
        technical: false
      };
    }

    state.technical = technicalNumbers.includes(total as number);
    return {
      totalOneDigit,
      total,
      calculationProcess,
      state
    };
  }

