  sumToOneDigit(num: number): number {
    // Calculate the length of the number
    let length = Math.floor(Math.log10(num)) + 1;

    // Function to sum the digits of a number
    const sumDigits = (n: number): number => {
      let sum = 0;
      while (n) {
        sum += n % 10;
        n = Math.floor(n / 10);
      }
      return sum;
    };

    // Continue summing digits until it reduces to a single digit
    while (length > 1) {
      num = sumDigits(num);
      length = Math.floor(Math.log10(num)) + 1;
    }

    return num;
  }

  reduceToSingleDigit(number: number): number {
    const masterNumbers: number[] = [11, 22, 33, 44];
    const karmaNumbers: number[] = [13, 14, 16, 18, 19];

    // Check if the number is a master or karma number before reducing
    if (masterNumbers.includes(number) || karmaNumbers.includes(number)) {
      return number;
    }

    // Reduce the number to a single digit
    while (number > 9) {
      number = number.toString().split('').reduce((acc, curr) => acc + parseInt(curr), 0);
      if (masterNumbers.includes(number) || karmaNumbers.includes(number)) {
        return number;
      }
    }
    return number;
  }

  getLastBirthdayYear(dateOfBirth: string): number {
    // Parse the date string to create a Date object
    const dob = new Date(dateOfBirth);

    // Get the current date
    const currentDate = new Date();

    // Get the year of birth
    const birthYear = dob.getFullYear();

    // Get the current year
    const currentYear = currentDate.getFullYear();

    // Check if the birthday has occurred in the current year
    if (
      currentDate.getMonth() > dob.getMonth() ||
      (currentDate.getMonth() === dob.getMonth() && currentDate.getDate() >= dob.getDate())
    ) {
      // Birthday has occurred, so the last birthday year is the current year
      return currentYear;
    } else {
      // Birthday has not occurred yet in the current year, so the last birthday year is the previous year
      return currentYear - 1;
    }
  }


  generateSquareOfPythagorasResultTable(data: number[][]): string {
    let html = `
        <div class="table-responsive">
            <table class="table table-bordered table-striped" dir="rtl" style="table-layout: fixed; width: 100%;border: 3px solid cornflowerblue;">
                <tbody>
    `;

    // Check if all elements in a given array are not empty
    const isAllNotEmpty = (arr: any[]): boolean => arr.every(el => el !== 0);

    // Check if all elements in a given array are empty
    const isAllEmpty = (arr: any[]): boolean => arr.every(el => el === 0);

    // Loop through each row
    for (let i = 0; i < 3; i++) {
      html += '<tr>';
      // Loop through each column in reverse order
      for (let j = 2; j >= 0; j--) {
        const number = data[i][j];
        let cellContent = number !== 0 ? number.toString() : ''; // If number is 0, set cellContent to empty string

        // Check if all elements in the current column, row, and diagonals are not empty
        const isColNotEmpty = isAllNotEmpty(data.map(row => row[j]));
        const isRowNotEmpty = isAllNotEmpty(data[i]);
        const isDiag1NotEmpty = i === j ? isAllNotEmpty(data.map((row, index) => row[index])) : false;
        const isDiag2NotEmpty = i + j === 2 ? isAllNotEmpty(data.map((row, index) => row[2 - index])) : false;

        // Determine if the cell should be colored lime or red
        let textColor = 'lime'; // Default color is lime

        // If all elements in a column are empty, set text color to red and cellContent to "?"
        if (isAllEmpty(data.map(row => row[j]))) {
          textColor = 'red';
          cellContent = '?';
        }

        // If all elements in a row are empty, set text color to red and cellContent to "?"
        if (isAllEmpty(data[i])) {
          textColor = 'red';
          cellContent = '?';
        }

        // If all elements in the diagonal are empty, set text color to red and cellContent to "?"
        if (isDiag1NotEmpty && isDiag2NotEmpty) {
          textColor = 'red';
          cellContent = '?';
        }

        // If the cell is not empty and not all elements in the row, column, or diagonal are full, set text color to white
        if (cellContent !== '?' && cellContent !== '' && (!isColNotEmpty && !isRowNotEmpty && !isDiag1NotEmpty && !isDiag2NotEmpty)) {
          textColor = 'white';
        }

        html += `<td style="text-align: center; width: 33.33%;"><span style="font-size: x-large; font-weight: bold; color: ${textColor};">${cellContent}</span></td>`;
      }
      html += '</tr>';
    }

    html += `
                </tbody>
            </table>
        </div>
    `;

    return html;
  }
  generateSquareOfPythagorasTable(squareOfPythagoras: SquareOfPythagorasCell[]): string {
    let html = `
        <div class="table-responsive">
            <table class="table table-bordered table-striped" dir="rtl" style="table-layout: fixed; width: 100%;border: 3px solid cornflowerblue;"
                <tbody>
    `;

    // Loop through each row
    for (let i = 1; i <= 3; i++) {
      html += '<tr>';
      // Loop through each column
      for (let j = 1; j <= 3; j++) {
        // Find the cell with the matching row and column
        const cell = squareOfPythagoras.find(cell => cell.row === i && cell.column === j);
        if (cell) {
          html += `<td style="text-align: center;"><span style="font-size: x-large; font-weight: bold;color: white">${cell.number}<br>${cell.value}</span></td>`;
        } else {
          html += '<td></td>'; // Empty cell if no matching cell is found
        }
      }
      html += '</tr>';
    }

    html += `
                </tbody>
            </table>
        </div>
    `;

    return html;
  }

