  colorizeLastNumber(inputString: string): string {
    const parts = inputString.split('='); // Split the string by '='
    const lastPart = parts[parts.length - 1].trim(); // Get the last part after the last '='
    parts[parts.length - 1] = `<span style="color: lime">${lastPart}</span>`


    // Replace the last number in the input string with the colored number
    const formattedString = parts.join(' = ');

    return formattedString;
  }

  getLastNumber(inputString: string): string {
    const parts = inputString.split('='); // Split the string by '='
    const lastPart = parts[parts.length - 1].trim(); // Get the last part after the last '='
    return lastPart;
  }

  calculateNumbers(arr: [number, number]): [number, number] {
    const [number, result] = arr;

    // Function to calculate the sum of digits until a single digit is obtained
    const sumDigits = (num: number): number => {
      let sum = num;
      while (sum >= 10) {
        sum = sum
          .toString()
          .split('')
          .map(Number)
          .reduce((acc, curr) => acc + curr, 0);
      }
      return sum;
    };

    // Calculate the higher number
    let higherNumber = number;
    while (sumDigits(higherNumber) !== 1) {
      higherNumber++;
    }

    // Calculate the lower number
    let lowerNumber = number;
    while (sumDigits(lowerNumber) !== 1) {
      lowerNumber--;
    }

    // If the result is 1, return the original array
    if (result === 1) {
      return [28, 56];
    }

    // Calculate the absolute differences from the first number
    const diffHigher = Math.abs(number - higherNumber);
    const diffLower = Math.abs(number - lowerNumber);

    // Determine the number with the smaller difference
    const thirdNumber = diffHigher < diffLower ? higherNumber : lowerNumber;

    // Calculate the difference to be added or subtracted from the first number
    const diffFromFirst = number - thirdNumber;

    // Calculate the third number by adjusting the difference from the first number
    const thirdNumberAdjusted = diffHigher < diffLower ? 28 + diffFromFirst : 28 - diffFromFirst;

    return this.getAdjustedThirdNumbers(thirdNumberAdjusted);
  }

  // Function to return an array with adjusted third numbers
  getAdjustedThirdNumbers(thirdNumberAdjusted: number): [number, number] {
    return [thirdNumberAdjusted, thirdNumberAdjusted + 28];
  }

