  findCellWithMostCharacters(table: TableData): CellData {
    let maxRowChars = 0;
    let maxColChars = 0;
    let maxRowCell: CellData | null = null;
    let maxColCell: CellData | null = null;

    // Find the row with the most characters
    for (const rowName in table) {
      if (table.hasOwnProperty(rowName)) {
        const row = table[rowName];
        let rowChars = 0;
        for (const colName in row) {
          if (row.hasOwnProperty(colName)) {
            const cell = row[colName];
            rowChars += cell.length;
          }
        }
        if (rowChars > maxRowChars) {
          maxRowChars = rowChars;
          maxRowCell = { row: rowName, col: 'Total' };
        }
      }
    }

    // Find the column with the most characters
    for (const colName in table['גוף']) {
      if (table['גוף'].hasOwnProperty(colName)) {
        let colChars = 0;
        for (const rowName in table) {
          if (table.hasOwnProperty(rowName)) {
            const cell = table[rowName][colName];
            colChars += cell.length;
          }
        }
        if (colChars > maxColChars) {
          maxColChars = colChars;
          maxColCell = { row: 'Total', col: colName };
        }
      }
    }

    return { row: maxRowCell!.row, col: maxColCell!.col };
  }

  removeAllChildElements(parentElementId: string): void {
    const parentElement = document.getElementById(parentElementId);
    while (parentElement?.firstChild) {
      parentElement.removeChild(parentElement.firstChild);
    }
  }

  appendTableToParent(parentElementId: string, table: HTMLTableElement): void {
    const parentElement = document.getElementById(parentElementId);
    parentElement?.appendChild(table);
  }

  isRowEmpty(matrix: number[][], row: number): boolean {
    return matrix[row].every(element => element === 0);
  }

  isRowFull(matrix: number[][], row: number): boolean {
    return matrix[row].every(element => element !== 0);
  }

  isColEmpty(matrix: number[][], col: number): boolean {
    return matrix.every(row => row[col] === 0);
  }

  isColFull(matrix: number[][], col: number): boolean {
    return matrix.every(row => row[col] !== 0);
  }

  isMainDiagonalEmpty(matrix: number[][]): boolean {
    const numRows = matrix.length;
    for (let i = 0; i < numRows; i++) {
      if (matrix[i][i] !== 0) {
        return false;
      }
    }
    return true;
  }

  isMainDiagonalFull(matrix: number[][]): boolean {
    const numRows = matrix.length;
    for (let i = 0; i < numRows; i++) {
      if (matrix[i][i] === 0) {
        return false;
      }
    }
    return true;
  }

  isSecondaryDiagonalEmpty(matrix: number[][]): boolean {
    const numRows = matrix.length;
    const numCols = matrix[0].length;
    for (let i = 0; i < numRows; i++) {
      if (matrix[i][numCols - 1 - i] !== 0) {
        return false;
      }
    }
    return true;
  }

  isSecondaryDiagonalFull(matrix: number[][]): boolean {
    const numRows = matrix.length;
    const numCols = matrix[0].length;
    for (let i = 0; i < numRows; i++) {
      if (matrix[i][numCols - 1 - i] === 0) {
        return false;
      }
    }
    return true;
  }

  isMatrixFull(matrix: number[][]): boolean {
    const numRows = matrix.length;
    const numCols = matrix[0].length;
    for (let i = 0; i < numRows; i++) {
      for (let j = 0; j < numCols; j++) {
        if (matrix[i][j] === 0) {
          return false;
        }
      }
    }
    return true;
  }

  calculateAge(dateOfBirth: string): number {
    const dob: Date = new Date(dateOfBirth);
    const today: Date = new Date();
    let age: number = today.getFullYear() - dob.getFullYear();
    const monthDiff: number = today.getMonth() - dob.getMonth();

    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < dob.getDate())) {
      age--;
    }

    return age;
  }

  formatDate(dateString: string): string {
    if (!dateString) return '';
    const parts = dateString.split('-');
    if (parts.length !== 3) return dateString;
    return `${parts[2]}-${parts[1]}-${parts[0]}`;
  }




