  getHebrewCharacteristics(hebrewString: string): { Char: string, Characteristics: string }[] {
    // Array to store the result
    const result: { Char: string, Characteristics: string }[] = [];

    // Iterate over each character in the input string
    for (const char of hebrewString) {
      // Check if the character is a Hebrew letter
      const isHebrewLetter = /^[\u0590-\u05FF]+$/.test(char);
      if (isHebrewLetter) {
        // Get the Unicode code point of the character
        const codePoint = char.charCodeAt(0);
        // Add the character and its characteristics to the result array
        result.push({ Char: char, Characteristics: `` });
      }
    }

    return result;
  }

  // Example function to generate placeholder characteristics based on the character's Unicode code point
  getCharacteristicsFromCodePoint(codePoint: number): string {
    // This is just a placeholder implementation, you can replace it with your logic
    // For demonstration, let's return the hexadecimal representation of the code point
    return codePoint.toString(16).toUpperCase();
  }

  getFourQuarterMonths(birthDate: string): number[] {
    const monthsAfterBirth: number[] = [];

    // Extract the month and year from the birth date
    const birthMonth: number = parseInt(birthDate.split('-')[1]);
    const birthYear: number = parseInt(birthDate.split('-')[0]);

    // Calculate the months in four quarters after the birth date
    //for (let i = 0; i < 4; i++) {
    const quarterStartMonth: number = (birthMonth) % 12; // Calculate the starting month of each quarter
    const currentQuarterMonths: number[] = [quarterStartMonth];

    // Add the next two months to the current quarter
    for (let j = 1; j <= 3; j++) {
      currentQuarterMonths.push((quarterStartMonth + j * 3) % 12 || 12); // Handle month rollover from December to January
    }

    // Push the current quarter's months to the result array
    //monthsAfterBirth.push(...currentQuarterMonths);
    //}

    return currentQuarterMonths;
  }

  getFirstVowelIndex(inputString: string): number {
    const vowels: string[] = ['א', 'ה', 'ו', 'י', 'ע']; // Define your list of vowels

    for (let i = 0; i < inputString.length; i++) {
      if (vowels.includes(inputString[i])) {
        return i; // Return the index of the first vowel found
      }
    }

    return -1; // Return -1 if no vowel is found
  }



  getMiddleIndex(inputString: string): number {
    const isOddLength = inputString.length % 2 !== 0;

    if (isOddLength) {
      return Math.floor(inputString.length / 2); // Return the middle index for odd length
    }

    return -1; // Return -1 for even length
  }

  getNextMonthsAndYears(months: number[], year: number): string[] {
    const result: string[] = [];

    let nextYear: number = year;

    for (let i = 0; i < months.length; i++) {
      const month: number = months[i];
      const nextMonth: number = (month + 3) % 12 || 12;

      if (nextMonth < month) {
        nextYear++;
      }

      result.push(`${month}-${nextMonth}/${nextYear}`);
    }

    return result;
  }

  calculateAge4AttributionDate(birthDate: string, currentDate: string): number {
    const birthYear = parseInt(birthDate.split('-')[0]);
    const birthMonth = parseInt(birthDate.split('-')[1]);
    const birthDay = parseInt(birthDate.split('-')[2]);

    const currentYear = parseInt(currentDate.split('-')[0]);
    const currentMonth = parseInt(currentDate.split('-')[1]);
    const currentDay = parseInt(currentDate.split('-')[2]);

    let age = currentYear - birthYear;

    // Check if the current date has passed the birth date for this year
    if (currentMonth < birthMonth || (currentMonth === birthMonth && currentDay < birthDay)) {
      age--;
    }

    return age;
  }

  countNumbersInString(str: string): number {
    // Remove spaces and brackets from the string, then split by comma to get individual numbers
    const numbers = str.replace(/[\[\]\s]/g, '').split(',');

    // Filter out non-numeric values and count the remaining numbers
    const numericValues = numbers.filter(num => !isNaN(parseFloat(num)));

    return numericValues.length;
  }

  calculateFullShareValue(numbers: number[]): CalculationFullResult {
    let sum = numbers.reduce((acc, curr) => acc + curr, 0);
    let calculationProcess = numbers.join(' + ') + ' = ' + sum;

    let total = sum;
    let totalOneDigit = sum;

    while (total > 9 && !this.areAllDigitsSame(total)) {
      // Check if all digits in the total are the same
      if (this.areAllDigitsSame(total)) {
        break;
      }

      // Sum the digits of the total
      const reducedTotal = total
        .toString()
        .split('')
        .reduce((acc, curr) => acc + parseInt(curr), 0);

      // Update calculation process
      calculationProcess += ' = ' + reducedTotal;

      total = reducedTotal;
      totalOneDigit = total;
    }

    return {
      totalOneDigit,
      total,
      calculationProcess
    };
  }

  highlightCurrentPeriod(inputString: string): string {
    // Check if the input string contains "..."
    const hasFirstDots = inputString.includes("...");
    const hasSecondDots = inputString.includes("...");

    // Split the input string into age and periods
    const [ageString, ...periods] = inputString.split(',');

    // Parse the age
    const age = parseInt(ageString.trim(), 10);

    // Insert "0" if the first "..." is missing
    const periodsWithFirstDots = hasFirstDots ? periods : ["0", ...periods];

    // Insert "120" if the second "..." is missing
    const periodsWithBothDots = hasSecondDots ? periodsWithFirstDots : [...periodsWithFirstDots, "120"];

    // Find the index of the current period
    const currentPeriodIndex = periodsWithBothDots.findIndex(period => {
      const [start, end] = period.split('-').map(str => parseInt(str.trim()));
      return age >= start && age < end;
    });

    // If the current period is found, format the string with green highlighting
    if (currentPeriodIndex !== -1) {
      const highlightedPeriods = periodsWithBothDots.map((period, index) => {
        if (index === currentPeriodIndex) {
          return `<span style="color: lime">${period}</span>`;
        } else {
          return period;
        }
      });

      return `[${highlightedPeriods.join(', ')}]`;
    }

    // If the current period is not found, return the periods without highlighting
    return `[${periodsWithBothDots.join(', ')}]`;
  }



  calculateCycleAndOccurrences(age: number, startingCycle: number): CycleInfo {
    // Calculate the total number of cycles passed since birth
    const totalCycles = age + startingCycle - 1;

    // Calculate the current cycle based on the total number of cycles
    const cycle = totalCycles % 9 === 0 ? 9 : totalCycles % 9;

    // Calculate how many times the current cycle has occurred in the person's life
    const occurrences = Math.ceil(totalCycles / 9);

    return {
      cycle,
      occurrences
    };
  }

  insertFullNameIntoTable(table: TableData, fullName: string): void {

    // Iterate over each character in the full name
    for (const char of fullName) {
      const mapping = characterMapping[char];
      if (mapping) {
        // Insert the character into the corresponding cell
        table[mapping.row][mapping.col].push(char);
      }
    }
  }

  // Function to check if all digits in a number are the same
  areAllDigitsSame(num: number): boolean {
    const digits = num.toString().split('');
    return digits.every(digit => digit === digits[0]);
  }

