generatePromptForGPT(sections: SectionInfo[]): string {
  const intro = `אנא הפוך את המידע הבא לאינפוגרפיקה אינטראקטיבית או HTML מעוצב:
כל מקטע צריך לכלול כותרת ברורה, תיאור טקסטואלי מודגש (אם קיים), ושדות מפתח-ערך.
העיצוב צריך להיות מודרני, רספונסיבי ונוח לקריאה.`;

  const jsonData = JSON.stringify(sections, null, 2);
  return `${intro}\n\n---\n\n${jsonData}`;
}


generateMiniHtmlSection(title: string, info: any): string {
  let html = `<h2>${title}</h2>`;

  if (info.Input) {
    html += `<p><strong>הקלט:</strong> ${info.Input}</p>`;
  }

  if (info.Description) {
    html += `<p><strong>הסבר:</strong><br><pre>${info.Description}</pre></p>`;
  }

  if (info.SoulExpression) {
    html += `<p><strong>ביטוי נשמה:</strong><br><pre>${info.SoulExpression}</pre></p>`;
  }

  if (info.ExtrovertedBehavior) {
    html += `<p><strong>התנהגות מוקצנת:</strong><br><pre>${info.ExtrovertedBehavior}</pre></p>`;
  }

  if (info.DestinyPath) {
    html += `<p><strong>שביל גורל:</strong><br><pre>${info.DestinyPath}</pre></p>`;
  }

  return `<div style="margin-bottom: 40px;">${html}</div>`;
}

  countNumbersWithType(numbersWithType: CountValuePair[]): { [key: number]: { number: number, types: string[] } } {
    const counts: { [key: number]: { number: number, types: string[] } } = {};

    // Iterate through the list of numbers with types
    for (const { value, type } of numbersWithType) {
      // Check if the value contains a comma
      if (value.includes(',')) {
        // If it does, split the string by commas and parse each part as a number
        const numbers: number[] = value.split(',').map(num => Number(num.trim()));

        // Iterate through each number in the array
        for (const num of numbers) {
          // If the number is already in the counts object, update its count and add the type to the types array
          if (counts[num]) {
            counts[num].number++;
            counts[num].types.push(type);
          } else {
            // If the number is not in the counts object, initialize its count to 1 and create a new types array
            counts[num] = { number: 1, types: [type] };
          }
        }
      } else {
        // If the value does not contain a comma, it's a single character
        const num = Number(value.trim());
        // If the number is already in the counts object, update its count and add the type to the types array
        if (counts[num]) {
          counts[num].number++;
          counts[num].types.push(type);
        } else {
          // If the number is not in the counts object, initialize its count to 1 and create a new types array
          counts[num] = { number: 1, types: [type] };
        }
      }
    }

    return counts;
  }

  countNumbers(numbers: number[]): { [key: number]: number } {
    const counts: { [key: number]: number } = {};

    // Iterate through the list of numbers
    for (const num of numbers) {
      // If the number is already in the counts object, increment its count, otherwise set it to 1
      counts[num] = (counts[num] || 0) + 1;
    }

    return counts;
  }

  getTitleValuePairsJSON(pairs: TitleValuePair[]): string {
    const jsonPairs = pairs.map(pair => `{"${pair.title}": "${pair.value}"}`);
    return `[${jsonPairs.join(', ')}]`;
  }



